  ('heelevel3-4c199b1b-moex-00103', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-111-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '下列何種行為，雖經法定代理人允許，限制行為能力人亦不得為之？', '["加入漁會成為會員", "在票據上簽名", "擔任合會之會首", "加入職業工會成為會員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00104', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-111-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '下列有關人事保證人責任之敘述，何者錯誤？', '["以受僱人將來因職務上行為應對僱用人負賠償責任者為限", "以僱用人不能依他項方法受賠償者為限", "以賠償事故發生時，受僱人2年內可得報酬之總額為限", "未定期間者，以自保證成立之日起3年內發生之賠償事故為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00105', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-111-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '債務人怠於向第三人索還欠款時，債權人因保全債權，得以自己之名義，行使代位權之範圍，下 列何者不包括之？', '["假扣押", "實行擔保物權", "提起異議之訴", "扶養請求權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00106', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-111-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '乙向甲租用專業攝影機，甲應允並將其所有之攝影機交付於乙使用。其後乙得甲之同意，復將該 攝影機轉租並交付於丙使用；丙外出攝影，均由緊隨其旁之助理丁協助將該攝影機架設於腳架上。 當丁執此攝影機架設於腳架上時，何者非該攝影機之占有人？', '["甲", "乙", "丙", "丁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00107', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-111-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '下列關於生前特種贈與之敘述，何者錯誤？', '["因留學所贈與之學費", "因出嫁所贈與之嫁妝", "因營業所贈與之資本", "因分居所贈與之費用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00108', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-111-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '設甲於民國103年7月間死亡，甲有繼承人為乙、丙。甲留有數筆債務與存款、動產；甲立有遺 囑為遺贈。下列敘述，何者錯誤？', '["乙、丙在法院依公示催告程序公告，命甲之債權人於一定期限內報明其債權之期限內，不得對 於甲之任何債權人償還債務", "乙、丙中之一人如陳報遺產清冊，其他繼承人視為已陳報", "乙、丙開具遺產清冊陳報法院時，法院應同時指定會同開具財產清冊之人", "乙、丙非依規定償還債務後，不得向受遺贈人交付遺贈"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00109', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-110-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'essay', '張三有子甲與女兒乙各一人。張三於罹癌入院後欲將所持有之 A地予以
出售，故簽署授權書，載明授權兒子甲代為出售A地，包含從契約訂定
到登記等事宜之各階段處理權及代理權。後來張三因癌症惡化於A地買
賣契約簽訂時，已經有意識狀態不清之情形，甲持其張三簽名之授權書，
與丙簽訂 A地買賣契約價金約定為 740萬元，並已給付由乙保管，由丙
依法辦理登記而於辦竣 A地登記前，張三因癌症過世。於張三死亡前，
均未曾受監護之宣告。
張三女兒乙認為張三授權甲之際已經病情嚴重而意識不清，主張該買賣
契約未有合法授權，故甲為無權代理，買賣契約無效，並主張甲保管 740
萬之行為侵害其財產繼承權，是否有理？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "0704", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00110', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-110-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'essay', '兄弟姊妹甲、乙、丙、丁四人共有Ａ地，應有部分各四分之一，甲過世
後，由乙、丙、丁繼承甲之應有部分。嗣乙以丙、丁為被告提起分割共
有物訴訟，其主張將乙、丙、丁繼承甲之應有部分之公同共有分割為分
別共有，由乙、丙、丁各分得三分之一之應有部分，亦即甲之應有部分
由公同共有分割為分別共有後，由乙、丙、丁各享有十二分之一應有部
分，並與其原應有部分合併計算後，由乙、丙、丁以各應有部分三分之
一將Ａ土地均等 3 等份，由其等各單獨所有之，乙、丙、丁雖就分配位
置有不同意見，然均同意先就共同繼承甲之應有部分而終止公同共有關
係，並為分割，試問乙的分割方案是否有理？（20 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "0704", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00111', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-110-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '胎兒甲是遺腹子，其父遭乙駕車不慎撞死。下列關於胎兒甲的權利之敘述，何者正確？', '["甲尚無權利能力，不得向乙主張權利", "關於甲權利之保護，甲視為有權利能力，然而他尚未出生，無法向乙請求損害賠償", "甲得以其母為法定代理人，向乙請求損害賠償", "無論甲將來是否為死產，其胎兒期間之權利不受影響 32820、33320 33520"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00112', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-110-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲公司於民國（下同）102年2月間舉辦員工旅遊，住宿乙之旅店，積欠住宿費新臺幣10萬元， 乙於103年2月催告後甲仍不給付，乙乃於104年2月訴請甲給付，於105年2月獲勝訴判決確 定。下列敘述，何者正確？', '["乙於103年2月催告時，時效中斷", "乙於104年2月訴請甲給付時，時效不完成", "判決確定後，時效重新起算5年", "判決確定後，時效重新起算15年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL)
